 EVENTS: CFS4_EVENTS,
 NS: {
 EXT_ROOT: CFS4_EXT_NS_ROOT, // entry.extensions.cfs
 SCHEMA_ENTRY_PREFIX: CFS4_SCHEMA_ENTRY_PREFIX,
 STABLE_TOKEN_TAG: CFS4_STABLE_TOKEN_TAG,
 SCRIPT_VAR_KEY: CFS4_SCRIPT_VAR_KEY,
 },
 // API
 loadConfig: loadConfig,
 saveConfig: saveConfig,
 emit: emit,
 deriveCharacterSlug: deriveCharacterSlug,
 getSchemaIds: getSchemaIds,
 log: L,
 // 模块的挂载点（占位，后续填）
 SchemaFrozenLayer: null,
 SchemaSwapGate: null,
 SchemaResolver: null,
 PathRegistry: null,
 DiffEngine: null,
 PresenceEncoder: null,
 InjectionStrategy: null,
 };
 // iframe 内同步：方便 iframe 内代码用 window.CFS4 也能访问
 if (typeof window !== 'undefined' && window !== _CFS4_GLOBAL) window.CFS4 = _CFS4_GLOBAL.CFS4;
 }

 // ===== 7. 启动 =====
 function v4_boot() {
 try {
 _CFS4_GLOBAL.CFS4._cfg = loadConfig();
 L.info('StatData Engine ' + CFS4_VERSION + ' initialized; pending chat_changed for schema IDs');
 try {
 var _t = (typeof toastr !== 'undefined') ? toastr : ((typeof window !== 'undefined' && window.parent && window.parent.toastr) ? window.parent.toastr : null);
 if (_t) _t.info('CFS v4.x StatData Engine loaded', '', { timeOut: 4000 });
 } catch (e) { /* ignore */ }
 } catch (e) {
 L.error('v4_boot failed', e);
 }
 }

 // chat 切换时重打 schema IDs，让用户看到实际 slug
 function v4_logSchemaIdsOnChat() {
 try {
 var ids = getSchemaIds();
 L.info('chat_changed → schema IDs: ' + ids.primary + ' / ' + ids.fallback);
 } catch (e) {
 L.warn('v4_logSchemaIdsOnChat failed', e);
 }
 }
 try {
 if (typeof eventOn === 'function') {
 eventOn('chat_changed', v4_logSchemaIdsOnChat);
 eventOn('character_selected', v4_logSchemaIdsOnChat);
 }
 } catch (e) {
 L.warn('chat_changed listener register failed', e);
 }

 try { eventOnce('app_ready', v4_boot); }
 catch (e) { setTimeout(v4_boot, 1800); }
 setTimeout(function () {
 if (_CFS4_GLOBAL && _CFS4_GLOBAL.CFS4 && !_CFS4_GLOBAL.CFS4._cfg) v4_boot();
 }, 2400);

})();

/* ==========================================================
 * CFS v4.x: Schema Frozen Layer
 *
 * Hotfix:
 * 实测发现 TavernHelper 的 getLorebookEntries 返回的 entry 模型不含 `extensions` 字段
 * （ST 内部字段，对外暴露 29 个受控字段，无 extensions），导致 extensions.cfs.schema
 * 主锚点失效（写入时无效、读取时找不到）。降级方案：主锚点改用 comment 字段头部魔法串
 * [CFS4_SCHEMA|id=<id>|v=<ver>|sha=<sha>|sealed=<iso>]（comment 是 TavernHelper 透传字段）。
 * SHA256 兜底锚点不变，content 仍保持纯 canonical JSON。
 *
 * 协议契约 v3 §B 双锚点（hotfix 后）：
 * - 主锚点：entry.comment 头部魔法串（正则匹配）
 * - 兜底锚点：CFS 内部记录 (schema_id, ver) → sha256
 * - 任一失效 = 漂移 → emit cfs_schema_drift_detected + toast
 *
 * Canonical JSON 强制规范：
 * - key 字母序排列 / 缩进 2 空格 / 行尾 \n / undefined/NaN/Infinity 抛错
 * ==========================================================*/
(function () {
 'use strict';

 var _GLOBAL = (typeof window !== 'undefined' && window.parent) || (typeof window !== 'undefined' ? window : null);
 if (!_GLOBAL || !_GLOBAL.CFS4 || !_GLOBAL.CFS4._loaded) {
 console.warn('[CFS v4.x] CFS4 not initialized, abort');
 return;
 }
 if (_GLOBAL.CFS4.SchemaFrozenLayer && _GLOBAL.CFS4.SchemaFrozenLayer._version === '2.1') {
 console.warn('[CFS v4.x] SchemaFrozenLayer 2.1 already mounted, skip');
 return;
 }

 var CFS4 = _GLOBAL.CFS4;
 var L = CFS4.log;
 var SHA256_RECORDS_KEY = 'cfs_v4_schema_sha256_records';

 // ===== 0. comment 主锚点协议 =====
 // 格式：[CFS4_SCHEMA|id=<id>|v=<ver>|sha=<sha256>|sealed=<iso>] <人类可读说明>
 var CFS4_SCHEMA_COMMENT_RE = /^\[CFS4_SCHEMA\|id=([^|]+)\|v=([^|]+)\|sha=([0-9a-f]+)\|sealed=([^\]]+)\]/;

 function parseSchemaComment(comment) {
 if (!comment || typeof comment !== 'string') return null;
 var m = comment.match(CFS4_SCHEMA_COMMENT_RE);
 if (!m) return null;
 return { id: m[1], ver: m[2], sha256: m[3], sealed_at: m[4] };
 }

 function buildSchemaComment(meta) {
 return '[CFS4_SCHEMA|id=' + meta.id + '|v=' + meta.ver + '|sha=' + meta.sha256 + '|sealed=' + meta.sealed_at + '] CFS v4.x 自管 — 勿改本注释前缀和 content（双锚点保护，改了会触发漂移警报）';
 }

 // ===== 1. Canonical JSON 序列化 =====
 function canonicalize(obj) { return _canonicalSerialize(obj, 0); }

 function _canonicalSerialize(value, indent) {
 if (value === null) return 'null';
 if (value === undefined) throw new Error('canonicalize: undefined not allowed (schema 必须显式 null)');
 var t = typeof value;
 if (t === 'boolean') return value ? 'true' : 'false';
 if (t === 'number') {
 if (!isFinite(value)) throw new Error('canonicalize: NaN/Infinity not allowed');
 return JSON.stringify(value);
 }
 if (t === 'string') return JSON.stringify(value);
 if (Array.isArray(value)) {
 if (value.length === 0) return '[]';
 var arrPad = _spaces((indent + 1) * 2);
 var arrClose = _spaces(indent * 2);
 var items = [];
 for (var i = 0; i < value.length; i++) {
 items.push(arrPad + _canonicalSerialize(value[i], indent + 1));
 }
 return '[\n' + items.join(',\n') + '\n' + arrClose + ']';
 }
 if (t === 'object') {
 var keys = Object.keys(value).sort();
 if (keys.length === 0) return '{}';
 var objPad = _spaces((indent + 1) * 2);
 var objClose = _spaces(indent * 2);
 var pairs = [];
 for (var k = 0; k < keys.length; k++) {
 var key = keys[k];
 pairs.push(objPad + JSON.stringify(key) + ': ' + _canonicalSerialize(value[key], indent + 1));
 }
 return '{\n' + pairs.join(',\n') + '\n' + objClose + '}';
 }
 throw new Error('canonicalize: unsupported type ' + t);
 }

 function _spaces(n) { var s = ''; for (var i = 0; i < n; i++) s += ' '; return s; }

 // ===== 2. SHA256 hex =====
 async function sha256Hex(str) {
 var subtle = (_GLOBAL.crypto && _GLOBAL.crypto.subtle) ||
 (typeof crypto !== 'undefined' && crypto.subtle) || null;
 if (!subtle) throw new Error('Web Crypto API 不可用');
 var enc = new TextEncoder();
 var buf = enc.encode(str);
 var hashBuf = await subtle.digest('SHA-256', buf);
 var bytes = new Uint8Array(hashBuf);
 var hex = '';
 for (var i = 0; i < bytes.length; i++) {
 var b = bytes[i].toString(16);
 hex += b.length < 2 ? '0' + b : b;
 }
 return hex;
 }

 // ===== 3. SHA256 records 兜底锚点持久化 =====
 function _recordKey(schemaId, ver) { return schemaId + ':v' + ver; }

 function loadSha256Records() {
 try {
 if (typeof getVariables !== 'function') return {};
 var sv = getVariables({ type: 'script', script_id: getScriptId() });
 return (sv && sv[SHA256_RECORDS_KEY]) || {};
 } catch (e) { L.warn('loadSha256Records failed', e); return {}; }
 }

 function saveSha256Record(schemaId, ver, sha256) {
 try {
 if (typeof updateVariablesWith !== 'function') return false;
 updateVariablesWith(function (vars) {
 if (!vars || typeof vars !== 'object') vars = {};
 if (!vars[SHA256_RECORDS_KEY] || typeof vars[SHA256_RECORDS_KEY] !== 'object') vars[SHA256_RECORDS_KEY] = {};
 vars[SHA256_RECORDS_KEY][_recordKey(schemaId, ver)] = sha256;
 return vars;
 }, { type: 'script', script_id: getScriptId() });
 return true;
 } catch (e) { L.error('saveSha256Record failed', e); return false; }
 }

 function removeSha256Record(schemaId, ver) {
 try {
 updateVariablesWith(function (vars) {
 if (vars && vars[SHA256_RECORDS_KEY]) delete vars[SHA256_RECORDS_KEY][_recordKey(schemaId, ver)];
 return vars;
 }, { type: 'script', script_id: getScriptId() });
 } catch (e) { L.warn('removeSha256Record failed', e); }
 }

 // ===== 4. 当前 worldbook =====
 async function getActiveWorldbook() {
 if (typeof TavernHelper === 'undefined' || !TavernHelper.getCharLorebooks) throw new Error('TavernHelper.getCharLorebooks 不可用');
 var bind;
 try { bind = TavernHelper.getCharLorebooks({ name: 'current' }); }
 catch (e) { throw new Error('getCharLorebooks 失败: ' + e.message); }
 if (!bind || !bind.primary) throw new Error('当前角色卡未绑定 primary worldbook');
 return bind.primary;
 }

 // ===== 5. 主锚点：comment 魔法串匹配（支持 ver 精确过滤实现双轨并存）=====
 // 签名：findEntryBySchemaId(schemaId, optionsOrWorldbook)
 // options = { ver?: number|string, worldbook?: string }
 // 兼容旧调用：第二参数是 string → 当 worldbook 用
 async function findEntryBySchemaId(schemaId, optionsOrWorldbook) {
 var opts = {};
 if (typeof optionsOrWorldbook === 'string') opts.worldbook = optionsOrWorldbook;
 else if (optionsOrWorldbook && typeof optionsOrWorldbook === 'object') opts = optionsOrWorldbook;
 var wb = opts.worldbook || await getActiveWorldbook();
 var entries;
 try { entries = await TavernHelper.getLorebookEntries(wb); }
 catch (e) { throw new Error('getLorebookEntries 失败: ' + e.message); }
 for (var i = 0; i < entries.length; i++) {
 var e = entries[i];
 var meta = parseSchemaComment(e.comment);
 if (!meta) continue;
 if (meta.id !== schemaId) continue;
 if (opts.ver != null && String(meta.ver) !== String(opts.ver)) continue;
 return { entry: e, worldbook: wb, parsedMeta: meta };
 }
 return null;
 }

 // ===== 6. 双锚点校验 =====
 async function verifyAnchors(entry, schemaId, parsedMeta) {
 var result = { ok: true, mainAnchor: true, hashAnchor: true, reason: null };
 var meta = parsedMeta || parseSchemaComment(entry && entry.comment);
 if (!meta || meta.id !== schemaId) {
 result.ok = false; result.mainAnchor = false;
 result.reason = 'main anchor (comment marker) missing or id mismatch';
 return result;
 }
 var recordedSha = null;
 try {
 var records = loadSha256Records();
 recordedSha = records[_recordKey(schemaId, meta.ver)] || null;
 } catch (_e) {}
 if (!recordedSha) recordedSha = meta.sha256 || null;
 if (!recordedSha) {
 result.ok = false; result.hashAnchor = false;
 result.reason = 'no sha256 record (internal lost + comment.sha missing)';
 return result;
 }
 var actualSha;
 try { actualSha = await sha256Hex(entry.content || ''); }
 catch (e) {
 result.ok = false; result.hashAnchor = false;
 result.reason = 'sha256 compute failed: ' + e.message;
 return result;
 }
 if (actualSha !== recordedSha) {
 result.ok = false; result.hashAnchor = false;
 result.reason = 'sha256 mismatch (actual=' + actualSha.slice(0, 12) + '... recorded=' + recordedSha.slice(0, 12) + '...)';
 return result;
 }
 return result;
 }

 // ===== 7. writeSchema =====
 async function writeSchema(schemaObj, opts) {
 opts = opts || {};
 var schemaId = opts.schemaId;
 var ver = opts.ver;
 if (!schemaId || typeof schemaId !== 'string') throw new Error('writeSchema: opts.schemaId 必填');
 if (typeof ver !== 'number' && typeof ver !== 'string') throw new Error('writeSchema: opts.ver 必填');
 if (!schemaObj || typeof schemaObj !== 'object') throw new Error('writeSchema: schemaObj 必须是 object');

 var wb = await getActiveWorldbook();
 var canonical = canonicalize(schemaObj);
 var sha = await sha256Hex(canonical);
 var sealed_at = new Date().toISOString();
 var meta = { id: schemaId, ver: ver, sha256: sha, sealed_at: sealed_at };
 var comment = buildSchemaComment(meta);

 // 默认 disabled (storage mode) — schema entry 不进 prompt，避免 worldInfoBefore 暴涨
 // opts.injectable=true 才 enabled=true（元规则 lore 等需要 LLM 看到的 entry）
 var _injectable = opts.injectable === true;
 var entryPayload = {
 comment: comment,
 content: canonical,
 enabled: _injectable,
 constant: true,
 type: 'constant',
 position: 'before_character_definition',
 role: 0,
 depth: 4,
 order: 100,
 // 三锚点：第二+第三锚点（keys 数组 + extensions 结构）
 // 即使 comment 被用户改了 / extensions 被 ST 吃了，OR 判定仍能识别
 keys: ['_cfs4_managed'],
 extensions: { cfs: { managed: true, schema_id: schemaId, ver: ver } }
 };

 var existing = await findEntryBySchemaId(schemaId, { worldbook: wb, ver: ver });
 var entryUid = null;
 var action;

 if (existing) {
 entryPayload.uid = existing.entry.uid;
 entryUid = existing.entry.uid;
 action = 'update';
 try { await TavernHelper.setLorebookEntries(wb, [entryPayload]); }
 catch (e) { L.error('writeSchema setLorebookEntries (update) failed', e); throw e; }
 } else {
 action = 'create';
 var created = false;
 var errs = [];

 if (!created && typeof TavernHelper.createLorebookEntries === 'function') {
 try {
 var res = await TavernHelper.createLorebookEntries(wb, [entryPayload]);
 if (Array.isArray(res) && res.length > 0) {
 entryUid = (res[0] && res[0].uid != null) ? res[0].uid : (typeof res[0] === 'number' ? res[0] : null);
 }
 created = true;
 } catch (e) { errs.push('createLorebookEntries: ' + e.message); }
 }
 if (!created && typeof TavernHelper.createLorebookEntry === 'function') {
 try {
 var res2 = await TavernHelper.createLorebookEntry(wb, entryPayload);
 if (res2 && res2.uid != null) entryUid = res2.uid;
 else if (typeof res2 === 'number') entryUid = res2;
 created = true;
 } catch (e) { errs.push('createLorebookEntry: ' + e.message); }
 }
 if (!created) {
 try {
 await TavernHelper.setLorebookEntries(wb, [entryPayload]);
 created = true;
 } catch (e) { errs.push('setLorebookEntries (no uid): ' + e.message); }
 }
 if (!created) throw new Error('writeSchema 创建 entry 失败：' + errs.join(' | '));

 // 兜底：如果创建路径没返回 uid，通过 (schemaId, ver) 反查
 if (entryUid == null) {
 try {
 var fb = await findEntryBySchemaId(schemaId, { worldbook: wb, ver: ver });
 if (fb) entryUid = fb.entry.uid;
 } catch (_e) {}
 }
 }

 saveSha256Record(schemaId, ver, sha);
 CFS4.emit(CFS4.EVENTS.SCHEMA_FROZEN, {
 schema_id: schemaId, ver: ver, sha256: sha, sealed_at: sealed_at,
 uid: entryUid, worldbook: wb, action: action
 });
 L.info('writeSchema ' + action + ': ' + schemaId + ' v' + ver + ' sha=' + sha.slice(0, 16) + '... uid=' + entryUid);
 return { schema_id: schemaId, ver: ver, sha256: sha, sealed_at: sealed_at, uid: entryUid, worldbook: wb, action: action };
 }

 // ===== 8. readSchema =====
 async function readSchema(schemaId) {
 if (!schemaId) throw new Error('readSchema: schemaId 必填');
 var found;
 try { found = await findEntryBySchemaId(schemaId); }
 catch (e) { L.warn('readSchema: find entry failed - ' + e.message); return null; }
 if (!found) { L.debug('readSchema: ' + schemaId + ' not found'); return null; }

 var verify = await verifyAnchors(found.entry, schemaId, found.parsedMeta);
 if (!verify.ok) {
 var payload = {
 schema_id: schemaId, uid: found.entry.uid, worldbook: found.worldbook,
 main_anchor_ok: verify.mainAnchor, hash_anchor_ok: verify.hashAnchor, reason: verify.reason
 };
 CFS4.emit(CFS4.EVENTS.SCHEMA_DRIFT_DETECTED, payload);
 L.error('SCHEMA DRIFT: ' + schemaId + ' - ' + verify.reason, payload);
 try {
 var cfg = CFS4._cfg || {};
 if (cfg.drift_toast_enabled !== false) {
 var _t = (typeof toastr !== 'undefined') ? toastr : ((_GLOBAL && _GLOBAL.toastr) ? _GLOBAL.toastr : null);
 if (_t) _t.error('🚨 CFS Schema 漂移：' + schemaId + ' (' + verify.reason + ')', '', { timeOut: 8000 });
 }
 } catch (_e) {}
 return null;
 }

 var parsed;
 try { parsed = JSON.parse(found.entry.content); }
 catch (e) {
 L.error('readSchema: canonical JSON parse failed - ' + e.message);
 CFS4.emit(CFS4.EVENTS.SCHEMA_DRIFT_DETECTED, {
 schema_id: schemaId, uid: found.entry.uid, worldbook: found.worldbook,
 reason: 'JSON parse failed: ' + e.message
 });
 return null;
 }
 return { schema: parsed, meta: found.parsedMeta, uid: found.entry.uid, worldbook: found.worldbook };
 }

 // ===== 9. removeSchema (按 ver 精确匹配，防止误关 active) =====
 async function removeSchema(schemaId, ver) {
 // ver 必填，否则可能误关其他版本的 entry
 var found = await findEntryBySchemaId(schemaId, ver != null ? { ver: ver } : undefined);
 if (!found) return false;
 try { await TavernHelper.setLorebookEntries(found.worldbook, [{ uid: found.entry.uid, enabled: false }]); }
 catch (e) { L.warn('removeSchema disable failed', e); }
 if (ver != null) removeSha256Record(schemaId, ver);
 return true;
 }

 // ===== 10. listManagedEntries =====
 async function listManagedEntries() {
 var wb = await getActiveWorldbook();
 var entries = await TavernHelper.getLorebookEntries(wb);
 var managed = [];
 for (var i = 0; i < entries.length; i++) {
 var e = entries[i];
 var meta = parseSchemaComment(e.comment);
 if (meta) {
 managed.push({
 uid: e.uid, schema_id: meta.id, ver: meta.ver, sealed_at: meta.sealed_at,
 sha256: meta.sha256, enabled: e.enabled, contentLen: (e.content || '').length, comment: e.comment
 });
 }
 }
 return { worldbook: wb, entries: managed };
 }

 // ===== 11. cleanupLegacyEntries=====
 async function cleanupLegacyEntries() {
 var wb = await getActiveWorldbook();
 var entries = await TavernHelper.getLorebookEntries(wb);
 var disabled = [];
 var errors = [];
 for (var i = 0; i < entries.length; i++) {
 var e = entries[i];
 // alpha 的旧 comment 前缀是 [_cfs_schema_xxx]，且不含新版 [CFS4_SCHEMA|
 if (e.comment && e.comment.indexOf('[_cfs_schema_') === 0 && e.comment.indexOf('[CFS4_SCHEMA|') < 0) {
 try {
 await TavernHelper.setLorebookEntries(wb, [{
 uid: e.uid,
 enabled: false,
 comment: '[CFS4_LEGACY_DISABLED_v20alpha] ' + e.comment
 }]);
 disabled.push({ uid: e.uid, oldComment: e.comment });
 } catch (err) {
 errors.push({ uid: e.uid, error: err.message });
 }
 }
 }
 L.info('cleanupLegacyEntries: disabled=' + disabled.length + ' errors=' + errors.length);
 return { worldbook: wb, disabled: disabled, errors: errors };
 }

 // ===== 12. Default schema 模板 =====
 function buildDefaultSchemaTemplate() {
 return {
 '_$cfs_meta': {
 version: 1,
 description: 'CFS v4.x default minimal schema',
 convention: '所有 stat_data 路径在 paths 字段中注册，每个 path 携带 type 和 default'
 },
 paths: {}
 };
 }

 // ===== 13. selfTest =====
 async function selfTest(schemaId) {
 var ids = CFS4.getSchemaIds();
 var sid = schemaId || ids.primary;
 L.info('selfTest 开始: ' + sid);
 var template = buildDefaultSchemaTemplate();
 var wResult = await writeSchema(template, { schemaId: sid, ver: 1 });
 L.info('selfTest write ok', wResult);
 var rResult = await readSchema(sid);
 L.info('selfTest read ok', rResult);
 var listResult = await listManagedEntries();
 L.info('selfTest list ok', listResult);
 return { write: wResult, read: rResult, list: listResult };
 }

 // ===== 14. 导出 =====
 CFS4.SchemaFrozenLayer = {
 _version: '2.1',
 canonicalize: canonicalize,
 sha256Hex: sha256Hex,
 parseSchemaComment: parseSchemaComment,
 buildSchemaComment: buildSchemaComment,
 getActiveWorldbook: getActiveWorldbook,
 findEntryBySchemaId: findEntryBySchemaId,
 verifyAnchors: verifyAnchors,
 writeSchema: writeSchema,
 readSchema: readSchema,
 removeSchema: removeSchema,
 listManagedEntries: listManagedEntries,
 buildDefaultSchemaTemplate: buildDefaultSchemaTemplate,
 cleanupLegacyEntries: cleanupLegacyEntries,
 loadSha256Records: loadSha256Records,
 selfTest: selfTest
 };

 L.info('Schema Frozen Layer mounted');
})();

/* ==========================================================
 * CFS v4.x: Schema Swap Gate
 * (mutation debounce layer · T_w 时间驱动 · pending → active 决策门)
 *
 * 协议契约 v3 §E：
 * - 职责钉死：只控制 schema 从 pending → active 的决策。
 * 不承担 diff 延迟、不承担全局节流、不承担其他模块防抖。
 * 不接受任何非 schema 触发源。
 * - 状态机：[active v] → propose → [active v, pending v+1]
 * → (commit | rollback | T_w 到期) → lazy swap
 * → [active v+1, deprecated v] → 一轮回滚窗口 → [active v+1]
 * - T_w 默认 90s，可配 30 ~ 600，仅控制 pending → active gate
 * - 跟 Diff Engine 完全异步解耦（diff 始终针对当前 active schema）
 *
 * 持久化：gate state 存到 getVariables({type:'script'}) 的
 * cfs_v4_swap_gate_state key，跨 F5 恢复
 * ==========================================================*/
(function () {
 'use strict';

 var _GLOBAL = (typeof window !== 'undefined' && window.parent) || (typeof window !== 'undefined' ? window : null);
 if (!_GLOBAL || !_GLOBAL.CFS4 || !_GLOBAL.CFS4._loaded) {
 console.warn('[CFS v4.x] CFS4 not initialized, abort');
 return;
 }
 if (_GLOBAL.CFS4.SchemaSwapGate && _GLOBAL.CFS4.SchemaSwapGate._version) {
 console.warn('[CFS v4.x] SchemaSwapGate already mounted, skip');
 return;
 }
 if (!_GLOBAL.CFS4.SchemaFrozenLayer) {
 console.warn('[CFS v4.x] 依赖 SchemaFrozenLayer 未就绪，abort');
 return;
 }

 var CFS4 = _GLOBAL.CFS4;
 var L = CFS4.log;
 var SFL = CFS4.SchemaFrozenLayer;
 var GATE_STATE_KEY = 'cfs_v4_swap_gate_state';

 // ===== 0. 内存 state 缓存 =====
 // state 结构：{ '<schema_id>': { active, pending, deprecated, swap_timer_id } }
 // active = { ver, sha256, sealed_at, uid } | null
 // pending = { ver, sha256, sealed_at, uid, swap_at_iso } | null
 // deprecated = { ver, sha256, sealed_at, uid, rounds_remaining } | null (rounds_remaining = 1 / 0 / -1)
 // swap_timer_id 内存态不持久化（F5 后通过 swap_at_iso 比对当前时间重建）
 var _state = {};
 var _timerHandles = {}; // { schema_id: setTimeout handle }
 var _depRoundCounter = {}; // { schema_id: 用于 deprecated 倒计时 }

 // ===== 1. State 持久化 =====
 function _persistState() {
 try {
 if (typeof updateVariablesWith !== 'function') return false;
 // 持久化时去掉 swap_timer_id（内存态）
 var persistable = {};
 var keys = Object.keys(_state);
 for (var i = 0; i < keys.length; i++) {
 var s = _state[keys[i]];
 persistable[keys[i]] = {
 active: s.active || null,
 pending: s.pending || null,
 deprecated: s.deprecated || null
 };
 }
 updateVariablesWith(function (vars) {
 if (!vars || typeof vars !== 'object') vars = {};
 vars[GATE_STATE_KEY] = persistable;
 return vars;
 }, { type: 'script', script_id: getScriptId() });
 return true;
 } catch (e) {
 L.error('SwapGate persist failed', e);
 return false;
 }
 }

 function _loadState() {
 try {
 if (typeof getVariables !== 'function') return {};
 var sv = getVariables({ type: 'script', script_id: getScriptId() });
 return (sv && sv[GATE_STATE_KEY]) || {};
 } catch (e) {
 L.warn('SwapGate loadState failed', e);
 return {};
 }
 }

 // ===== 2. 工具：当前时间 + T_w =====
 function _now() { return new Date().toISOString(); }
 function _getTw() {
 var cfg = CFS4._cfg || {};
 var t = cfg.swap_gate_T_w_seconds;
 if (typeof t !== 'number' || t < 30) t = 90;
 if (t > 600) t = 600;
 return t;
 }

 // ===== 3. 当前 active 引用=====
 function getActiveRef(schemaId) {
 var s = _state[schemaId];
 if (!s || !s.active) return null;
 return Object.assign({ schema_id: schemaId }, s.active);
 }

 function getPendingRef(schemaId) {
 var s = _state[schemaId];
 if (!s || !s.pending) return null;
 return Object.assign({ schema_id: schemaId }, s.pending);
 }

 function getDeprecatedRef(schemaId) {
 var s = _state[schemaId];
 if (!s || !s.deprecated) return null;
 return Object.assign({ schema_id: schemaId }, s.deprecated);
 }

 function getState(schemaId) {
 if (schemaId) return _state[schemaId] || null;
 return _state;
 }

 // ===== 4. propose：用户改 schema，进入 pending 状态 =====
 async function propose(schemaObj, opts) {
 opts = opts || {};
 var schemaId = opts.schemaId;
 var ver = opts.ver;
 if (!schemaId || typeof schemaId !== 'string') throw new Error('propose: opts.schemaId 必填');
 if (typeof ver !== 'number' && typeof ver !== 'string') throw new Error('propose: opts.ver 必填');

 // 验证 ver 比 active.ver 大
 var current = _state[schemaId];
 if (current && current.active) {
 var aVer = parseFloat(current.active.ver);
 var nVer = parseFloat(ver);
 if (!isNaN(aVer) && !isNaN(nVer) && nVer <= aVer) {
 throw new Error('propose: 新 ver (' + ver + ') 必须大于当前 active.ver (' + current.active.ver + ')');
 }
 }
 if (current && current.pending) {
 throw new Error('propose: schema ' + schemaId + ' 已有 pending v' + current.pending.ver + '，请先 commit 或 rollback');
 }

 // 调 SchemaFrozenLayer.writeSchema 写入新版本
 var w = await SFL.writeSchema(schemaObj, { schemaId: schemaId, ver: ver });

 // 计算 swap_at
 var Tw = _getTw();
 var swapAtMs = Date.now() + Tw * 1000;
 var swapAtIso = new Date(swapAtMs).toISOString();

 // 更新 state
 if (!_state[schemaId]) _state[schemaId] = { active: null, pending: null, deprecated: null };
 _state[schemaId].pending = {
 ver: ver, sha256: w.sha256, sealed_at: w.sealed_at, uid: w.uid, swap_at_iso: swapAtIso
 };

 // 如果当前没有 active（首次 propose），直接立即提升为 active（不走 T_w）
 if (!_state[schemaId].active) {
 L.info('propose: ' + schemaId + ' 首次写入，无 active，直接提升为 active 不走 T_w');
 _state[schemaId].active = _state[schemaId].pending;
 _state[schemaId].pending = null;
 _persistState();
 CFS4.emit(CFS4.EVENTS.SCHEMA_SWAP_COMMITTED, {
 schema_id: schemaId, ver: ver, sha256: w.sha256,
 commit_reason: 'initial', uid: w.uid
 });
 return { status: 'active', schema_id: schemaId, ver: ver, sha256: w.sha256 };
 }

 // 启动 T_w 定时器
 _scheduleAutoSwap(schemaId, Tw);
 _persistState();

 L.info('propose: ' + schemaId + ' v' + ver + ' 进入 pending，T_w=' + Tw + 's，swap_at=' + swapAtIso);
 CFS4.emit(CFS4.EVENTS.SCHEMA_SWAP_PENDING, {
 schema_id: schemaId, ver: ver, sha256: w.sha256, swap_at_iso: swapAtIso, T_w: Tw, uid: w.uid
 });
 return { status: 'pending', schema_id: schemaId, ver: ver, swap_at_iso: swapAtIso, T_w: Tw };
 }

 // ===== 5. 定时器：T_w 到期自动 swap =====
 function _scheduleAutoSwap(schemaId, delaySec) {
 if (_timerHandles[schemaId]) {
 clearTimeout(_timerHandles[schemaId]);
 delete _timerHandles[schemaId];
 }
 _timerHandles[schemaId] = setTimeout(function () {
 delete _timerHandles[schemaId];
 _lazySwap(schemaId, 'timeout').catch(function (e) {
 L.error('autoSwap failed for ' + schemaId, e);
 });
 }, delaySec * 1000);
 }

 // ===== 6. lazySwap：pending → active；旧 active → deprecated =====
 async function _lazySwap(schemaId, reason) {
 var s = _state[schemaId];
 if (!s || !s.pending) {
 L.warn('_lazySwap: no pending for ' + schemaId);
 return false;
 }
 var oldActive = s.active;
 var newActive = s.pending;
 s.active = newActive;
 s.pending = null;
 if (oldActive) {
 s.deprecated = Object.assign({}, oldActive, { rounds_remaining: 1 });
 // 重置 deprecated 轮次计数
 _depRoundCounter[schemaId] = 0;
 } else {
 s.deprecated = null;
 }
 _persistState();

 L.info('lazySwap [' + (reason || 'unknown') + ']: ' + schemaId
 + ' active=v' + newActive.ver
 + (oldActive ? ', deprecated=v' + oldActive.ver + ' (一轮回滚窗口)' : ''));
 CFS4.emit(CFS4.EVENTS.SCHEMA_SWAP_COMMITTED, {
 schema_id: schemaId,
 from_ver: oldActive ? oldActive.ver : null,
 to_ver: newActive.ver,
 sha256: newActive.sha256,
 reason: reason || 'unknown',
 has_deprecated_window: !!oldActive
 });
 return true;
 }

 // ===== 7. commit：用户显式 commit，绕过 T_w =====
 async function commit(schemaId) {
 if (!schemaId) throw new Error('commit: schemaId 必填');
 var s = _state[schemaId];
 if (!s || !s.pending) {
 L.warn('commit: no pending for ' + schemaId);
 return false;
 }
 if (_timerHandles[schemaId]) {
 clearTimeout(_timerHandles[schemaId]);
 delete _timerHandles[schemaId];
 }
 return _lazySwap(schemaId, 'explicit_commit');
 }

 // ===== 8. rollback：用户显式 rollback，删 pending =====
 async function rollback(schemaId) {
 if (!schemaId) throw new Error('rollback: schemaId 必填');
 var s = _state[schemaId];
 if (!s || !s.pending) {
 L.warn('rollback: no pending for ' + schemaId);
 return false;
 }
 if (_timerHandles[schemaId]) {
 clearTimeout(_timerHandles[schemaId]);
 delete _timerHandles[schemaId];
 }
 var pendingRef = s.pending;
 s.pending = null;
 _persistState();
 // disable pending entry
 try {
 await SFL.removeSchema(schemaId, pendingRef.ver);
 } catch (e) { L.warn('rollback: removeSchema failed', e); }
 L.info('rollback: ' + schemaId + ' pending v' + pendingRef.ver + ' 已撤销');
 CFS4.emit(CFS4.EVENTS.SCHEMA_SWAP_ROLLED_BACK, {
 schema_id: schemaId, rolled_back_ver: pendingRef.ver
 });
 return true;
 }

 // ===== 9. deprecated 一轮回滚窗口对齐 generate_before_combine_prompts =====
 // 第一次触发：标记本轮已用，留用户最后机会
 // 第二次触发：disable deprecated entry，state.deprecated = null
 function _onGenerateBeforeCombine() {
 var keys = Object.keys(_state);
 for (var i = 0; i < keys.length; i++) {
 var sid = keys[i];
 var s = _state[sid];
 if (!s || !s.deprecated) continue;
 _depRoundCounter[sid] = (_depRoundCounter[sid] || 0) + 1;
 if (_depRoundCounter[sid] === 1) {
 L.debug('deprecated [' + sid + '] 第 1 轮窗口，下一轮才真正 disable');
 } else if (_depRoundCounter[sid] >= 2) {
 var dep = s.deprecated;
 L.info('deprecated [' + sid + '] 窗口耗尽，disable v' + dep.ver);
 s.deprecated = null;
 _depRoundCounter[sid] = 0;
 _persistState();
 // 异步 disable 旧 entry（不阻塞 prompt 拼装）
 SFL.removeSchema(sid, dep.ver).catch(function (e) {
 L.warn('deprecated disable failed for ' + sid, e);
 });
 }
 }
 }

 // ===== 10. boot：从持久化恢复 state =====
 function _bootRestore() {
 var loaded = _loadState();
 var sids = Object.keys(loaded);
 for (var i = 0; i < sids.length; i++) {
 var sid = sids[i];
 _state[sid] = {
 active: loaded[sid].active || null,
 pending: loaded[sid].pending || null,
 deprecated: loaded[sid].deprecated || null
 };
 // 如果有 pending 且 swap_at 已过期 → 立即 lazySwap
 if (_state[sid].pending && _state[sid].pending.swap_at_iso) {
 var swapAt = new Date(_state[sid].pending.swap_at_iso).getTime();
 var now = Date.now();
 if (swapAt <= now) {
 L.info('boot: ' + sid + ' pending 已过期 (swap_at=' + _state[sid].pending.swap_at_iso + ')，立即 lazySwap');
 _lazySwap(sid, 'boot_expired').catch(function (e) {
 L.error('boot lazySwap failed', e);
 });
 } else {
 var remainSec = Math.ceil((swapAt - now) / 1000);
 L.info('boot: ' + sid + ' pending 重建定时器，剩余 ' + remainSec + 's');
 _scheduleAutoSwap(sid, remainSec);
 }
 }
 }
 L.info('SwapGate boot: 恢复 ' + sids.length + ' 条 schema state');
 }

 // ===== 11. selfTest（F12 调试用）=====
 async function selfTest() {
 var ids = CFS4.getSchemaIds();
 var sid = ids.primary + '::swap_test'; // 隔离测试 schema_id 避免影响真实数据
 var t1 = SFL.buildDefaultSchemaTemplate();
 t1.paths['test.a'] = { type: 'string', default: 'v1' };
 var t2 = SFL.buildDefaultSchemaTemplate();
 t2.paths['test.a'] = { type: 'string', default: 'v2' };

 L.info('selfTest: propose v1 (首次，应直接 active)');
 var r1 = await propose(t1, { schemaId: sid, ver: 1 });
 L.info(' → state:', getState(sid));

 L.info('selfTest: propose v2 (应进入 pending)');
 var r2 = await propose(t2, { schemaId: sid, ver: 2 });
 L.info(' → state:', getState(sid));

 L.info('selfTest: explicit commit v2');
 var r3 = await commit(sid);
 L.info(' → state:', getState(sid));
 L.info(' active 现在应是 v2，deprecated 应是 v1（rounds_remaining=1）');

 // 不实际触发 generate_before_combine_prompts，跑完测试后留状态供观察
 return { initial: r1, pending: r2, committed: r3, finalState: getState(sid) };
 }

 // ===== 12. cleanup（测试后清理 swap_test schema 残留）=====
 async function cleanupSwapTest() {
 var ids = CFS4.getSchemaIds();
 var sid = ids.primary + '::swap_test';
 var s = _state[sid];
 if (s) {
 if (s.active) try { await SFL.removeSchema(sid, s.active.ver); } catch (_e) {}
 if (s.pending) try { await SFL.removeSchema(sid, s.pending.ver); } catch (_e) {}
 if (s.deprecated) try { await SFL.removeSchema(sid, s.deprecated.ver); } catch (_e) {}
 delete _state[sid];
 _persistState();
 }
 return { cleaned: sid };
 }

 // ===== 13. 钩 generate_before_combine_prompts（跟 v3.1.7 PSIS 共存）=====
 try {
 if (typeof eventOn === 'function') {
 eventOn('generate_before_combine_prompts', _onGenerateBeforeCombine);
 }
 } catch (e) { L.warn('SwapGate hook generate_before_combine_prompts failed', e); }

 // ===== 14. boot 恢复持久化 state =====
 try { eventOnce('app_ready', _bootRestore); }
 catch (e) { setTimeout(_bootRestore, 1800); }
 // 兜底
 setTimeout(function () {
 if (Object.keys(_state).length === 0) _bootRestore();
 }, 2600);

 // ===== 15. 导出 =====
 CFS4.SchemaSwapGate = {
 _version: '3.0',
 propose: propose,
 commit: commit,
 rollback: rollback,
 getActiveRef: getActiveRef,
 getPendingRef: getPendingRef,
 getDeprecatedRef: getDeprecatedRef,
 getState: getState,
 getTw: _getTw,
 selfTest: selfTest,
 cleanupSwapTest: cleanupSwapTest
 };

 L.info('Schema Swap Gate mounted (T_w=' + _getTw() + 's)');
})();

/* ==========================================================
 * CFS v4.x: Schema Resolver + Path Registry
 *
 * 协议契约 v3 §B.3 + §C：
 *
 * Schema Resolver (§B.3)：
 * - 双层命名空间：primary (角色卡) → fallback (global)
 * - resolvePath(<schema_id>:<path_id>) 按 primary→fallback 顺序解析
 * - token 字面量跨卡不同 = 隔离正确，runtime 通过 Resolver 解析
 * - 监听 cfs_schema_swap_committed 自动失效缓存
 *
 * Path Registry (§C)：
 * - 数据结构：{ <path_id>: { path, schema_ref, last_value, last_round,
 * last_present_round, change_count, stability_class } }
 * - 路径权威列表，三态机的输入
 * - SwapGate commit 时根据新 active schema 同步（增/删 path_id）
 * - 持久化到 script-scope variables
 *
 * Schema paths 数据结构约定（写入 schema 时）：
 * schema.paths = {
 * "<path_id>": { // 稳定 ID（不是 path 字符串）
 * "path": "attributes.hp", // 人类可读路径（可变）
 * "type": "number",
 * "default": 100,
 * "desc": "..." // optional
 * }
 * }
 * path_id 推荐 'p_<NNNN>' 顺序递增，对 schema 演进稳定
 * ==========================================================*/
(function () {
 'use strict';

 var _GLOBAL = (typeof window !== 'undefined' && window.parent) || (typeof window !== 'undefined' ? window : null);
 if (!_GLOBAL || !_GLOBAL.CFS4 || !_GLOBAL.CFS4._loaded) {
 console.warn('[CFS v4.x] CFS4 not initialized, abort');
 return;
 }
 if (_GLOBAL.CFS4.SchemaResolver && _GLOBAL.CFS4.PathRegistry) {
 console.warn('[CFS v4.x] Resolver/Registry already mounted, skip');
 return;
 }
 if (!_GLOBAL.CFS4.SchemaFrozenLayer || !_GLOBAL.CFS4.SchemaSwapGate) {
 console.warn('[CFS v4.x] 依赖未就绪，abort');
 return;
 }

 var CFS4 = _GLOBAL.CFS4;
 var L = CFS4.log;
 var SFL = CFS4.SchemaFrozenLayer;
 var SSG = CFS4.SchemaSwapGate;
 var PATH_REGISTRY_KEY = 'cfs_v4_path_registry_state';

 // ===== Schema Resolver =====

 // 缓存 { schemaId: { schema, meta, uid, worldbook, ts } }
 var _resolverCache = {};

 function _invalidate(schemaId) {
 if (schemaId) delete _resolverCache[schemaId];
 else _resolverCache = {};
 }

 // 解析单个 schema_id（不走双层）
 async function resolveSchema(schemaId) {
 if (!schemaId) throw new Error('resolveSchema: schemaId 必填');
 if (_resolverCache[schemaId]) return _resolverCache[schemaId];
 var read = await SFL.readSchema(schemaId);
 if (!read) return null;
 _resolverCache[schemaId] = {
 schema: read.schema,
 meta: read.meta,
 uid: read.uid,
 worldbook: read.worldbook,
 ts: Date.now()
 };
 return _resolverCache[schemaId];
 }

 // 双层 resolution：先 primary，再 fallback
 // 返回 { primary, fallback }（任一可能为 null）
 async function resolveLayered() {
 var ids = CFS4.getSchemaIds();
 var primary = await resolveSchema(ids.primary).catch(function () { return null; });
 var fallback = await resolveSchema(ids.fallback).catch(function () { return null; });
 return { primary: primary, fallback: fallback, ids: ids };
 }

 // 解析 path_ref：<schema_id>:<path_id>
 // schema_id 本身含冒号（cfs_schema_xxx:primary），用 lastIndexOf 分隔
 function parsePathRef(pathRef) {
 if (!pathRef || typeof pathRef !== 'string') return null;
 var lastColon = pathRef.lastIndexOf(':');
 if (lastColon < 0) return null;
 var schemaId = pathRef.slice(0, lastColon);
 var pathId = pathRef.slice(lastColon + 1);
 if (!schemaId || !pathId) return null;
 return { schema_id: schemaId, path_id: pathId };
 }

 // 给定 path_ref，按 primary→fallback 双层解析
 // 返回 { path_id, schema_id, schema_ref, path_meta }
 async function resolvePath(pathRef) {
 var parsed = parsePathRef(pathRef);
 if (!parsed) throw new Error('resolvePath: invalid ref ' + pathRef);

 // 1. 先尝试 pathRef 里指定的 schema_id
 var cached = await resolveSchema(parsed.schema_id);
 if (cached && cached.schema && cached.schema.paths && cached.schema.paths[parsed.path_id]) {
 return {
 path_id: parsed.path_id,
 schema_id: parsed.schema_id,
 schema_ref: parsed.schema_id,
 path_meta: cached.schema.paths[parsed.path_id]
 };
 }

 // 2. 双层 fallback：如果 parsed.schema_id 不是当前 ids.primary，再试当前 primary + global fallback
 var ids = CFS4.getSchemaIds();
 var candidates = [];
 if (parsed.schema_id !== ids.primary) candidates.push(ids.primary);
 if (parsed.schema_id !== ids.fallback) candidates.push(ids.fallback);

 for (var i = 0; i < candidates.length; i++) {
 var cand = candidates[i];
 var c = await resolveSchema(cand).catch(function () { return null; });
 if (c && c.schema && c.schema.paths && c.schema.paths[parsed.path_id]) {
 return {
 path_id: parsed.path_id,
 schema_id: cand,
 schema_ref: cand,
 path_meta: c.schema.paths[parsed.path_id]
 };
 }
 }
 // 都找不到 → drift signal
 L.warn('resolvePath: path_id ' + parsed.path_id + ' 在 primary 和 fallback 中都找不到');
 return null;
 }

 // 给定 schema_ref 返回该 schema 内所有 path（{path_id: path_meta} map）
 async function listSchemaPaths(schemaId) {
 var c = await resolveSchema(schemaId);
 if (!c || !c.schema || !c.schema.paths) return {};
 return c.schema.paths;
 }

 // 失效 cache（外部 hook 用）
 function invalidateCache(schemaId) { _invalidate(schemaId); L.debug('resolver cache invalidated: ' + (schemaId || 'ALL')); }

 // ===== Path Registry =====

 // 内存 state
 var _registry = {}; // { path_id: { path, schema_ref, last_value, last_round, last_present_round, change_count, stability_class } }

 function _persistRegistry() {
 try {
 if (typeof updateVariablesWith !== 'function') return false;
 // 体积警告 + emit 信号让 HealthMonitor 可观测
 var pathCount = Object.keys(_registry).length;
 updateVariablesWith(function (vars) {
 if (!vars || typeof vars !== 'object') vars = {};
 vars[PATH_REGISTRY_KEY] = _registry;
 vars[PATH_REGISTRY_KEY + '_meta'] = { count: pathCount, ts: new Date().toISOString(), _version: 1 };
 return vars;
 }, { type: 'script', script_id: getScriptId() });
 // 体积阈值检测（接近 50KB 提前预警，留分页 contingency 窗口）
 try {
 var sizeBytes = JSON.stringify(_registry).length;
 if (sizeBytes > 40000 && !_persistRegistry._sizeWarned) {
 L.warn('PathRegistry 持久化体积接近阈值: ' + sizeBytes + ' bytes — 接近 50KB 软限，可能需要分页存储');
 _persistRegistry._sizeWarned = true;
 }
 } catch (_e) {}
 CFS4.emit('cfs_path_registry_persisted', { count: pathCount });
 return true;
 } catch (e) { L.error('PathRegistry persist failed', e); return false; }
 }

 function _loadRegistry() {
 try {
 if (typeof getVariables !== 'function') return {};
 var sv = getVariables({ type: 'script', script_id: getScriptId() });
 return (sv && sv[PATH_REGISTRY_KEY]) || {};
 } catch (e) { L.warn('PathRegistry load failed', e); return {}; }
 }

 function registerPath(pathId, schemaRef, opts) {
 if (!pathId) throw new Error('registerPath: pathId 必填');
 if (!schemaRef) throw new Error('registerPath: schemaRef 必填');
 opts = opts || {};
 if (!_registry[pathId]) {
 _registry[pathId] = {
 path: opts.path || pathId,
 schema_ref: schemaRef,
 last_value: opts.initialValue !== undefined ? opts.initialValue : null,
 last_round: opts.round != null ? opts.round : 0,
 last_present_round: 0,
 change_count: 0,
 stability_class: opts.stability_class || 'volatile'
 };
 } else {
 // 重注册：只更新 schema_ref 和 path（人类可读路径）；其他保留
 _registry[pathId].schema_ref = schemaRef;
 if (opts.path) _registry[pathId].path = opts.path;
 }
 _persistRegistry();
 return _registry[pathId];
 }

 function unregisterPath(pathId) {
 if (_registry[pathId]) {
 delete _registry[pathId];
 _persistRegistry();
 return true;
 }
 return false;
 }

 // 给 path_id 更新值（值真实出现时调用）
 function updatePath(pathId, value, round) {
 var r = _registry[pathId];
 if (!r) {
 L.warn('updatePath: ' + pathId + ' 未注册');
 return null;
 }
 var changed = (value !== r.last_value);
 if (changed) {
 r.last_value = value;
 r.change_count += 1;
 }
 if (round != null) {
 r.last_round = round;
 r.last_present_round = round;
 }
 _persistRegistry();
 return r;
 }

 // 标记 path 在某一轮缺失（不更新 last_value）
 function markPathOmitted(pathId, round) {
 var r = _registry[pathId];
 if (!r) return null;
 if (round != null) r.last_round = round;
 // last_present_round 不更新（区分"上次以 present 出现"vs"上次遍历到"）
 _persistRegistry();
 return r;
 }

 function setStabilityClass(pathId, cls) {
 var r = _registry[pathId];
 if (!r) return null;
 if (['volatile', 'stable', 'frozen'].indexOf(cls) < 0) {
 throw new Error('setStabilityClass: cls 必须是 volatile / stable / frozen');
 }
 r.stability_class = cls;
 _persistRegistry();
 return r;
 }

 function getPath(pathId) { return _registry[pathId] || null; }
 function getAllPaths() { return _registry; }

 // 根据当前 active schema 同步 registry：增/删 path_id
 async function syncFromSchema(schemaId) {
 var sid = schemaId || CFS4.getSchemaIds().primary;
 var paths = await listSchemaPaths(sid);
 var added = [], removed = [], kept = [];

 var schemaPathIds = Object.keys(paths);
 // 1. schema 里新增的 path_id → register
 for (var i = 0; i < schemaPathIds.length; i++) {
 var pid = schemaPathIds[i];
 var meta = paths[pid];
 if (!_registry[pid]) {
 registerPath(pid, sid, {
 path: meta.path || pid,
 initialValue: meta.default,
 stability_class: meta.stability_class || 'volatile'
 });
 added.push(pid);
 } else {
 // 检查 path 字符串是否变了
 if (meta.path && meta.path !== _registry[pid].path) {
 _registry[pid].path = meta.path;
 }
 _registry[pid].schema_ref = sid;
 kept.push(pid);
 }
 }
 // 2. registry 里有但当前 schema 没有的 path_id（在同 schema_ref 内）→ 标记为"待删除"
 // 实际是否删除取决于策略：暂时不强删，emit drift 让上层决定
 var registryPathIds = Object.keys(_registry);
 for (var j = 0; j < registryPathIds.length; j++) {
 var rid = registryPathIds[j];
 if (_registry[rid].schema_ref === sid && schemaPathIds.indexOf(rid) < 0) {
 removed.push(rid);
 }
 }
 _persistRegistry();
 var summary = { schema_id: sid, added: added, removed_pending: removed, kept: kept };
 CFS4.emit(CFS4.EVENTS.PATH_REGISTRY_UPDATED, summary);
 L.info('PathRegistry sync from ' + sid + ': +' + added.length + ' kept=' + kept.length + ' removed_pending=' + removed.length);
 return summary;
 }

 // boot 恢复 registry (多次重试加载，对抗 ST 落盘时序异步)
 function _bootRestoreRegistry() {
 var loaded = _loadRegistry();
 var count = loaded ? Object.keys(loaded).length : 0;
 _registry = loaded || {};
 L.info('PathRegistry boot: 恢复 ' + count + ' 条 path (第 1 次尝试)');
 if (count === 0) {
 // 0 条不一定是空状态，可能是 ST 还没落盘 → 多次延迟重试
 var attempts = [500, 1500, 3000];
 attempts.forEach(function (delay, i) {
 setTimeout(function () {
 if (Object.keys(_registry).length > 0) return; // 已有数据不再覆盖
 var retry = _loadRegistry();
 var retryCount = retry ? Object.keys(retry).length : 0;
 if (retryCount > 0) {
 _registry = retry;
 L.info('PathRegistry boot 第 ' + (i + 2) + ' 次尝试 (' + delay + 'ms 延迟): 恢复 ' + retryCount + ' 条 path');
 CFS4.emit('cfs_path_registry_late_recovered', { count: retryCount, attempt: i + 2 });
 }
 }, delay);
 });
 }
 // 体积警告（boot 时也检测）
 try {
 var sizeBytes = JSON.stringify(_registry).length;
 if (sizeBytes > 40000) L.warn('PathRegistry boot 加载体积: ' + sizeBytes + ' bytes (接近 50KB)');
 } catch (_e) {}
 }
 // 主动 flush helper（chat_changed / disconnect 等场景调）
 function _flushRegistry() {
 _persistRegistry();
 L.debug('PathRegistry 主动 flush 完成 (' + Object.keys(_registry).length + ' 条)');
 }

 // 钩 cfs_schema_swap_committed → 失效 cache + 同步 registry
 function _onSchemaCommitted(payload) {
 L.debug('Resolver/Registry: schema committed', payload);
 if (payload && payload.schema_id) {
 invalidateCache(payload.schema_id);
 // 异步 sync
 syncFromSchema(payload.schema_id).catch(function (e) {
 L.warn('PathRegistry syncFromSchema after commit failed', e);
 });
 } else {
 invalidateCache();
 }
 }

 try {
 if (typeof eventOn === 'function') {
 eventOn(CFS4.EVENTS.SCHEMA_SWAP_COMMITTED, _onSchemaCommitted);
 eventOn(CFS4.EVENTS.SCHEMA_FROZEN, function (payload) {
 // schema 刚被 freeze（write），失效 cache（即使没 commit，refresh schemas）
 if (payload && payload.schema_id) invalidateCache(payload.schema_id);
 });
 }
 } catch (e) { L.warn('钩事件失败', e); }

 // ===== selfTest =====
 async function selfTest() {
 var ids = CFS4.getSchemaIds();
 var sid = ids.primary + '::_test_resolver';

 // 构造一个 schema 含两个 path
 var schema = SFL.buildDefaultSchemaTemplate();
 schema.paths['p_0001'] = { path: 'attributes.hp', type: 'number', default: 100 };
 schema.paths['p_0002'] = { path: 'attributes.mp', type: 'number', default: 60 };

 // propose v1（首次→active）
 var r1 = await SSG.propose(schema, { schemaId: sid, ver: 1 });
 L.info('selfTest propose v1:', r1);

 // 此时 swap_committed 事件应已触发 syncFromSchema
 // 等下一个 tick 让事件 listener 跑完
 await new Promise(function (resolve) { setTimeout(resolve, 100); });

 // 1. resolveSchema 应能命中
 var resolved = await resolveSchema(sid);
 L.info('selfTest resolveSchema:', resolved ? { uid: resolved.uid, paths: Object.keys(resolved.schema.paths) } : null);

 // 2. resolvePath 应能找到 p_0001
 var rp = await resolvePath(sid + ':p_0001');
 L.info('selfTest resolvePath p_0001:', rp);

 // 3. PathRegistry 应已经 sync 含 p_0001 + p_0002
 var reg = getAllPaths();
 var myPaths = {};
 Object.keys(reg).forEach(function (k) { if (reg[k].schema_ref === sid) myPaths[k] = reg[k]; });
 L.info('selfTest PathRegistry (filtered to this schema):', myPaths);

 return {
 proposed: r1,
 resolved: resolved ? { uid: resolved.uid, paths: Object.keys(resolved.schema.paths) } : null,
 resolvedPath: rp,
 registryPaths: myPaths
 };
 }

 // cleanup（清掉 _test_resolver 残留）
 async function cleanupPhase4Test() {
 var ids = CFS4.getSchemaIds();
 var sid = ids.primary + '::_test_resolver';
 // 撤掉 Registry 里 schema_ref = sid 的所有 path
 var removedPaths = [];
 Object.keys(_registry).forEach(function (k) {
 if (_registry[k].schema_ref === sid) {
 delete _registry[k];
 removedPaths.push(k);
 }
 });
 _persistRegistry();
 // disable schema entry
 try { await SFL.removeSchema(sid, 1); } catch (_e) {}
 invalidateCache(sid);
 return { schema_id: sid, removed_paths: removedPaths };
 }

 // ===== boot =====
 try { eventOnce('app_ready', _bootRestoreRegistry); }
 catch (e) { setTimeout(_bootRestoreRegistry, 1800); }
 setTimeout(function () {
 if (Object.keys(_registry).length === 0) _bootRestoreRegistry();
 }, 2600);

 // chat_changed 时主动 flush，对抗 ST 内部落盘延迟
 try {
 if (typeof eventOn === 'function') {
 eventOn('chat_changed', _flushRegistry);
 eventOn('chat_id_changed', _flushRegistry);
 }
 } catch (e) { L.warn('chat_changed 钩失败', e); }

 // ===== 导出 =====
 CFS4.SchemaResolver = {
 _version: '4.0',
 resolveSchema: resolveSchema,
 resolveLayered: resolveLayered,
 resolvePath: resolvePath,
 parsePathRef: parsePathRef,
 listSchemaPaths: listSchemaPaths,
 invalidateCache: invalidateCache,
 _getCache: function () { return _resolverCache; }
 };

 CFS4.PathRegistry = {
 _version: '4.1',
 register: registerPath,
 unregister: unregisterPath,
 update: updatePath,
 markOmitted: markPathOmitted,
 setStabilityClass: setStabilityClass,
 getPath: getPath,
 getAll: getAllPaths,
 syncFromSchema: syncFromSchema,
 selfTest: selfTest,
 cleanupPhase4Test: cleanupPhase4Test,
 flush: _flushRegistry, // 主动 flush
 _persistImmediate: _persistRegistry,
 _bootRestore: _bootRestoreRegistry
 };

 L.info('Schema Resolver + Path Registry mounted');
})();

/* ==========================================================
 * CFS v4.x: Diff Engine (path-registry-driven 三态机)
 *
 * 协议契约 v3 §C 铁律：
 * - 输入: (registry, old_stat_data, new_stat_data, llm_update_ops)
 * - 输出: 每个注册路径恰好一个三态判定
 *
 * | 状态 | 判定 | 注入处理 |
 * |---------|------------------------------------------------|-------------------------|
 * | present | new 有值 + 跟 old 不同 | 走 mutable delta 层 |
 * | omitted | new 无值 / 值未变 + 无 explicit remove op | 保留 old 值 + stable token |
 * | deleted | LLM <UpdateVariable> 内出现 op='remove' path... | registry 移除该 path |
 *
 * 铁律：「new 里无值」绝不等于「deleted」
 * 未注册 path 出现 → emit cfs_schema_drift_detected
 *
 * 是纯计算引擎，不修改任何 state（不动 PathRegistry，不动 worldbook）。
 * 调用者根据三态结果决定后续动作。
 * ==========================================================*/
(function () {
 'use strict';

 var _GLOBAL = (typeof window !== 'undefined' && window.parent) || (typeof window !== 'undefined' ? window : null);
 if (!_GLOBAL || !_GLOBAL.CFS4 || !_GLOBAL.CFS4._loaded) {
 console.warn('[CFS v4.x] CFS4 not initialized, abort');
 return;
 }
 if (_GLOBAL.CFS4.DiffEngine && _GLOBAL.CFS4.DiffEngine._version) {
 console.warn('[CFS v4.x] DiffEngine already mounted, skip');
 return;
 }
 if (!_GLOBAL.CFS4.PathRegistry || !_GLOBAL.CFS4.SchemaResolver) {
 console.warn('[CFS v4.x] 依赖未就绪，abort');
 return;
 }

 var CFS4 = _GLOBAL.CFS4;
 var L = CFS4.log;
 var PR = CFS4.PathRegistry;

 // ===== 0. 工具：按点分 path 字符串读 nested object 值 =====
 function _getByPath(obj, path) {
 if (obj == null || !path) return undefined;
 var parts = String(path).split('.');
 var cur = obj;
 for (var i = 0; i < parts.length; i++) {
 if (cur == null || typeof cur !== 'object') return undefined;
 cur = cur[parts[i]];
 }
 return cur;
 }

 // 检查 obj 内 path 是否真的存在（区分 undefined 和 missing）
 function _hasPath(obj, path) {
 if (obj == null || !path) return false;
 var parts = String(path).split('.');
 var cur = obj;
 for (var i = 0; i < parts.length; i++) {
 if (cur == null || typeof cur !== 'object') return false;
 if (!Object.prototype.hasOwnProperty.call(cur, parts[i])) return false;
 cur = cur[parts[i]];
 }
 return true;
 }

 // 深比较两个值是否相等
 function _deepEqual(a, b) {
 if (a === b) return true;
 if (a == null || b == null) return a === b;
 if (typeof a !== typeof b) return false;
 if (typeof a !== 'object') return a === b;
 if (Array.isArray(a) !== Array.isArray(b)) return false;
 if (Array.isArray(a)) {
 if (a.length !== b.length) return false;
 for (var i = 0; i < a.length; i++) if (!_deepEqual(a[i], b[i])) return false;
 return true;
 }
 var aKeys = Object.keys(a);
 var bKeys = Object.keys(b);
 if (aKeys.length !== bKeys.length) return false;
 for (var j = 0; j < aKeys.length; j++) {
 if (!Object.prototype.hasOwnProperty.call(b, aKeys[j])) return false;
 if (!_deepEqual(a[aKeys[j]], b[aKeys[j]])) return false;
 }
 return true;
 }

 // 递归提取 stat_data 所有 leaf path（用 . 分隔，array 作 leaf）
 function _walkStatDataLeafPaths(obj, prefix) {
 var out = [];
 if (obj == null) return out;
 if (typeof obj !== 'object' || Array.isArray(obj)) {
 if (prefix) out.push(prefix);
 return out;
 }
 var keys = Object.keys(obj);
 if (keys.length === 0 && prefix) {
 out.push(prefix);
 return out;
 }
 for (var i = 0; i < keys.length; i++) {
 var k = keys[i];
 var sub = prefix ? prefix + '.' + k : k;
 out = out.concat(_walkStatDataLeafPaths(obj[k], sub));
 }
 return out;
 }

 // JSONPatch path "/X/Y" → 点风格 "X.Y"
 function _jsonPatchPathToDot(jpPath) {
 if (!jpPath || typeof jpPath !== 'string') return null;
 if (jpPath.charAt(0) !== '/') return null;
 // JSONPatch path 用 / 分隔，~1 表示 /，~0 表示 ~
 var parts = jpPath.slice(1).split('/');
 for (var i = 0; i < parts.length; i++) {
 parts[i] = parts[i].replace(/~1/g, '/').replace(/~0/g, '~');
 }
 return parts.join('.');
 }

 // ===== 1. computeDiff —— 主入口 =====
 //
 // opts = {
 // old_stat_data?: {}, // 上轮值（如果有；首轮可不传）
 // new_stat_data: {}, // 本轮值
 // llm_update_ops?: [{op, path, value}], // JSONPatch RFC 6902 ops（path 是 / 风格）
 // schema_ref?: 'cfs_schema_xxx:primary', // 筛选 registry 内此 schema_ref 的 paths；不传 = 全部
 // round?: <number> // 当前轮次（仅用于元数据，diff 本身不依赖）
 // }
 //
 // 返回 {
 // present: [{ path_id, path, old_value, new_value }],
 // omitted: [{ path_id, path, last_value, reason }],
 // deleted: [{ path_id, path, op }],
 // drift: [{ path, value, reason }],
 // round: <number>,
 // schema_ref: ...
 // }
 function computeDiff(opts) {
 opts = opts || {};
 var oldData = opts.old_stat_data || null;
 var newData = opts.new_stat_data;
 if (newData == null || typeof newData !== 'object') {
 throw new Error('computeDiff: new_stat_data 必须是 object');
 }
 var llmOps = Array.isArray(opts.llm_update_ops) ? opts.llm_update_ops : [];
 var schemaRef = opts.schema_ref || null;
 var round = opts.round != null ? opts.round : null;

 var result = {
 present: [], omitted: [], deleted: [], drift: [],
 round: round, schema_ref: schemaRef
 };

 // === Step 1: 解析 LLM remove ops（构建 path → op 映射）===
 // 注意：path 必须严格 explicit remove，op != 'remove' 不计入
 var explicitRemovePathsDot = {}; // { dotPath: jsonPatchOp }
 for (var i = 0; i < llmOps.length; i++) {
 var op = llmOps[i];
 if (op && op.op === 'remove' && op.path) {
 var dotP = _jsonPatchPathToDot(op.path);
 if (dotP) explicitRemovePathsDot[dotP] = op;
 }
 }

 // === Step 2: 遍历 PathRegistry 中匹配 schema_ref 的 paths，做三态判定 ===
 var registry = PR.getAll();
 var allRegisteredDotPaths = {}; // 用于 drift 检测：注册过的 path → path_id

 var pathIds = Object.keys(registry);
 for (var k = 0; k < pathIds.length; k++) {
 var pid = pathIds[k];
 var r = registry[pid];
 if (schemaRef && r.schema_ref !== schemaRef) continue;

 var pStr = r.path;
 allRegisteredDotPaths[pStr] = pid;

 // 2a. deleted 优先：explicit LLM remove op
 if (explicitRemovePathsDot[pStr]) {
 result.deleted.push({
 path_id: pid, path: pStr, op: explicitRemovePathsDot[pStr]
 });
 continue;
 }

 // 2b. present / omitted 判定
 var hasNew = _hasPath(newData, pStr);
 if (hasNew) {
 var newVal = _getByPath(newData, pStr);
 var oldVal = oldData ? _getByPath(oldData, pStr) : r.last_value;
 if (!_deepEqual(newVal, oldVal)) {
 // 新值跟 old 不同 → present
 result.present.push({
 path_id: pid, path: pStr,
 old_value: oldVal, new_value: newVal
 });
 } else {
 // 新值跟 old 相同（或 old 没有）→ omitted（值未变）
 result.omitted.push({
 path_id: pid, path: pStr,
 last_value: newVal, reason: 'unchanged'
 });
 }
 } else {
 // new 里没出现 → omitted（保留 last_value）
 result.omitted.push({
 path_id: pid, path: pStr,
 last_value: r.last_value, reason: 'not_in_new'
 });
 }
 }

 // === Step 3: drift 检测 —— new_stat_data 里有但 registry 没注册的 path ===
 var newLeafPaths = _walkStatDataLeafPaths(newData, '');
 for (var m = 0; m < newLeafPaths.length; m++) {
 var p = newLeafPaths[m];
 if (!allRegisteredDotPaths[p]) {
 result.drift.push({
 path: p,
 value: _getByPath(newData, p),
 reason: 'path appears in new_stat_data but not in PathRegistry (' +
 (schemaRef ? 'schema_ref=' + schemaRef : 'any schema') + ')'
 });
 }
 }

 // emit drift event 但不抛错（让调用方决定）
 if (result.drift.length > 0) {
 CFS4.emit(CFS4.EVENTS.SCHEMA_DRIFT_DETECTED, {
 source: 'DiffEngine',
 schema_ref: schemaRef,
 unregistered_paths: result.drift.map(function (x) { return x.path; }),
 count: result.drift.length
 });
 L.warn('DiffEngine: ' + result.drift.length + ' unregistered path 出现在 new_stat_data 中', result.drift);
 }

 // emit computed event
 CFS4.emit(CFS4.EVENTS.DIFF_COMPUTED, {
 schema_ref: schemaRef,
 round: round,
 counts: {
 present: result.present.length,
 omitted: result.omitted.length,
 deleted: result.deleted.length,
 drift: result.drift.length
 }
 });

 L.debug('computeDiff: ' + (schemaRef || 'ANY')
 + ' present=' + result.present.length
 + ' omitted=' + result.omitted.length
 + ' deleted=' + result.deleted.length
 + ' drift=' + result.drift.length);

 return result;
 }

 // ===== 2. applyDiffToRegistry —— 可选辅助：根据 diff 结果更新 registry =====
 //
 function applyDiffToRegistry(diffResult) {
 if (!diffResult) return;
 var round = diffResult.round;
 // present → update（写入新值）
 for (var i = 0; i < diffResult.present.length; i++) {
 var p = diffResult.present[i];
 PR.update(p.path_id, p.new_value, round);
 }
 // omitted → markOmitted（last_round 推进，last_value 保留）
 for (var j = 0; j < diffResult.omitted.length; j++) {
 var o = diffResult.omitted[j];
 PR.markOmitted(o.path_id, round);
 }
 // deleted → unregister
 for (var k = 0; k < diffResult.deleted.length; k++) {
 var d = diffResult.deleted[k];
 PR.unregister(d.path_id);
 }
 // drift 不动 registry（按协议铁律：不自动注册）
 }

 // ===== 3. selfTest =====
 async function selfTest() {
 var ids = CFS4.getSchemaIds();
 var sid = ids.primary + '::_test_diff';

 // 1. 构造 schema with 3 paths
 var schema = CFS4.SchemaFrozenLayer.buildDefaultSchemaTemplate();
 schema.paths['p_0010'] = { path: 'attributes.hp', type: 'number', default: 100 };
 schema.paths['p_0011'] = { path: 'attributes.mp', type: 'number', default: 50 };
 schema.paths['p_0012'] = { path: 'system.location', type: 'string', default: '院子' };

 // 绕过 SwapGate 状态机
 // 直接 writeSchema 写 entry + 失效 Resolver cache + 手动 syncFromSchema 同步 PathRegistry
 // 重复跑 selfTest 时 writeSchema 走 update 路径（同 sid + ver=1），完全 idempotent
 await CFS4.SchemaFrozenLayer.writeSchema(schema, { schemaId: sid, ver: 1 });
 CFS4.SchemaResolver.invalidateCache(sid);
 await CFS4.PathRegistry.syncFromSchema(sid);

 // 2. 构造 old_stat_data + new_stat_data + llm_ops
 var oldData = {
 attributes: { hp: 100, mp: 50 },
 system: { location: '院子' }
 };
 var newData = {
 attributes: { hp: 85, mp: 50 }, // hp 变了，mp 没变
 system: { location: '走廊', new_field: '???' } // location 变了；new_field 没注册 → drift
 // attributes.something_deleted 缺失 → 但因为 path 没注册不影响
 };
 var llmOps = [
 // 显式删一个未注册 path（不影响 deleted 三态——只有注册过的才会进 deleted）
 { op: 'remove', path: '/inventory/old_potion' }
 ];

 L.info('selfTest: 跑 computeDiff');
 var diff = computeDiff({
 old_stat_data: oldData,
 new_stat_data: newData,
 llm_update_ops: llmOps,
 schema_ref: sid,
 round: 1
 });

 L.info(' present:', diff.present);
 L.info(' omitted:', diff.omitted);
 L.info(' deleted:', diff.deleted);
 L.info(' drift:', diff.drift);

 // 期望：
 // present = [p_0010 (hp: 100→85), p_0012 (location: 院子→走廊)]
 // omitted = [p_0011 (mp unchanged)]
 // deleted = [] (因为没有注册的 path 被 remove)
 // drift = [system.new_field]

 return diff;
 }

 // ===== 4. cleanup =====
 async function cleanupPhase5Test() {
 var ids = CFS4.getSchemaIds();
 var sid = ids.primary + '::_test_diff';
 // 撤掉 Registry 里 schema_ref = sid 的 path
 var reg = PR.getAll();
 var removed = [];
 Object.keys(reg).forEach(function (k) {
 if (reg[k].schema_ref === sid) {
 PR.unregister(k);
 removed.push(k);
 }
 });
 try { await CFS4.SchemaFrozenLayer.removeSchema(sid, 1); } catch (_e) {}
 CFS4.SchemaResolver.invalidateCache(sid);
 return { schema_id: sid, removed_paths: removed };
 }

 // ===== 5. 导出 =====
 CFS4.DiffEngine = {
 _version: '5.0',
 computeDiff: computeDiff,
 applyDiffToRegistry: applyDiffToRegistry,
 // 暴露内部工具供下游复用
 _getByPath: _getByPath,
 _hasPath: _hasPath,
 _deepEqual: _deepEqual,
 _walkStatDataLeafPaths: _walkStatDataLeafPaths,
 _jsonPatchPathToDot: _jsonPatchPathToDot,
 selfTest: selfTest,
 cleanupPhase5Test: cleanupPhase5Test
 };

 L.info('Diff Engine mounted');
})();

/* ==========================================================
 * CFS v4.x: Presence Encoder + Injection Strategy
 * (dry-run 阶段)
 *
 * 协议契约 v3 §D：
 * - Stable Presence Token 格式：<STABLE ref="<schema_id>:<path_id>"/>
 * - 零 value payload（不带类型/hash/last_value/任何运行时信息）
 * - Injection Strategy 三层：schema / stable presence / mutable delta
 * - 钩 generate_before_combine_prompts（跟 v3.1.7 PSIS R1 抢跑钩共存）
 *
 * dry-run 边界：
 * - 实现编码器 + 注入字符串生成器
 * - 钩 generate_before_combine_prompts 只 log + emit，不改实际 prompt
 * - 未来讨论真正接管 stat_data 渲染（需用户拍板策略）
 *
 * 元规则 lore 内容（写在跟 schema 同区段独立 entry）：
 * 告诉 LLM "看到 <STABLE/> 标签 = 该字段值跨轮稳定，按 schema 中 ref
 * 指向的当前值理解，禁止凭对话上下文推断、改写或猜测"
 * ==========================================================*/
(function () {
 'use strict';

 var _GLOBAL = (typeof window !== 'undefined' && window.parent) || (typeof window !== 'undefined' ? window : null);
 if (!_GLOBAL || !_GLOBAL.CFS4 || !_GLOBAL.CFS4._loaded) {
 console.warn('[CFS v4.x] CFS4 not initialized, abort');
 return;
 }
 if (_GLOBAL.CFS4.PresenceEncoder && _GLOBAL.CFS4.InjectionStrategy) {
 console.warn('[CFS v4.x] PresenceEncoder/InjectionStrategy already mounted, skip');
 return;
 }
 if (!_GLOBAL.CFS4.DiffEngine) {
 console.warn('[CFS v4.x] 依赖未就绪，abort');
 return;
 }

 var CFS4 = _GLOBAL.CFS4;
 var L = CFS4.log;
 var DE = CFS4.DiffEngine;
 var PR = CFS4.PathRegistry;
 var SR = CFS4.SchemaResolver;
 var SFL = CFS4.SchemaFrozenLayer;

 // ===== PresenceEncoder =====
 var TOKEN_RE = /<STABLE\s+ref="([^"]+)"\s*\/>/g;
 var TOKEN_RE_ONE = /<STABLE\s+ref="([^"]+)"\s*\/>/;

 function encodeToken(schemaId, pathId) {
 if (!schemaId || !pathId) throw new Error('encodeToken: schemaId + pathId 必填');
 return '<STABLE ref="' + schemaId + ':' + pathId + '"/>';
 }

 function encodeManyTokens(schemaId, pathIds) {
 if (!Array.isArray(pathIds)) return '';
 var out = [];
 for (var i = 0; i < pathIds.length; i++) {
 out.push(encodeToken(schemaId, pathIds[i]));
 }
 return out.join('');
 }

 function decodeToken(tokenStr) {
 if (!tokenStr) return null;
 var m = TOKEN_RE_ONE.exec(tokenStr);
 if (!m) return null;
 var ref = m[1];
 // 用 lastIndexOf(':') 切 schema_id / path_id（schema_id 含 :primary 后缀）
 var p = SR.parsePathRef(ref);
 return p ? { schema_id: p.schema_id, path_id: p.path_id } : null;
 }

 // 从一段文本里提取所有 token
 function extractAllTokens(text) {
 if (!text) return [];
 var tokens = [];
 var m;
 var re = new RegExp(TOKEN_RE.source, 'g');
 while ((m = re.exec(text)) !== null) {
 var p = SR.parsePathRef(m[1]);
 if (p) tokens.push({ token: m[0], schema_id: p.schema_id, path_id: p.path_id });
 }
 return tokens;
 }

 // ===== 元规则 lore 内容 =====
 function buildMetaRuleLore() {
 return [
 '# CFS v4.x Stable Presence 协议（自动注入，勿修改）',
 '',
 '## 看到 `<STABLE ref="..."/>` 标签时：',
 '',
 '该字段的值**跨轮稳定**（上轮、上上轮、若干轮以来均未变化），按 schema 中 ref',
 '指向的当前值理解。**禁止**凭对话上下文推断、改写或猜测该值。任何"我记得这个值',
 '是 X"的内部推理在此标签前一律作废。',
 '',
 '## 看到本轮变化字段（"mutable delta"）时：',
 '',
