 });
 if (existing) {
 _dynamicEntryUid = existing.uid;
 L.debug('dynamic entry 已存在 uid=' + existing.uid);
 return { entry: existing, worldbook: wb, action: 'reuse' };
 }
 // 创建（三档 fallback 同 SFL.writeSchema）
 var payload = {
 comment: DYNAMIC_ENTRY_COMMENT,
 content: '',
 enabled: true,
 constant: true,
 type: 'constant',
 position: 'at_depth_as_user',
 role: 0,
